from typing import List

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x != root_y:
            if self.rank[root_x] > self.rank[root_y]:
                self.parent[root_y] = root_x
            elif self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1

class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        uf = UnionFind(n)
        restricted = set()
        for x, y in restrictions:
            restricted.add((min(x, y), max(x, y)))

        result = []
        for u, v in requests:
            root_u = uf.find(u)
            root_v = uf.find(v)
            if root_u != root_v and (min(u, v), max(u, v)) not in restricted:
                uf.union(u, v)
                result.append(True)
            else:
                result.append(False)
        return result
